import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import android.util.Log;

public class DeepLinkHandler extends AppCompatActivity {
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        Intent intent = getIntent();
        Uri data = intent.getData();
        if (data != null) {
            String scheme = data.getScheme();
            String host = data.getHost();
            String path = data.getPath();
            if ("myapp".equals(scheme) && "profile".equals(host)) {
                // Handle profile screen
                int userId = Integer.parseInt(path.substring(1));
                navigateToProfileScreen(userId);
            } else if ("myapp".equals(scheme) && "payment".equals(host)) {
                // Handle payment confirmation screen
                String transactionId = data.getQueryParameter("transaction_id");
                navigateToPaymentConfirmationScreen(transactionId);
            } else if ("myapp".equals(scheme) && "admin".equals(host)) {
                // Handle admin settings screen
                navigateToAdminSettingsScreen();
            } else {
                Log.w("DeepLinkHandler", "Invalid deep link: " + data);
            }
        }
    }

    private void navigateToProfileScreen(int userId) {
        Intent intent = new Intent(this, ProfileActivity.class);
        intent.putExtra("userId", userId);
        startActivity(intent);
    }

    private void navigateToPaymentConfirmationScreen(String transactionId) {
        Intent intent = new Intent(this, PaymentConfirmationActivity.class);
        intent.putExtra("transactionId", transactionId);
        startActivity(intent);
    }

    private void navigateToAdminSettingsScreen() {
        Intent intent = new Intent(this, AdminSettingsActivity.class);
        startActivity(intent);
    }
}